import{_ as t,o as l,c as e,ag as i}from"./chunks/framework.Vng7Hdlh.js";const b=JSON.parse('{"title":"18. セキュリティとアカウント管理","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/18-security.md","filePath":"tenant/18-security.md"}'),r={name:"tenant/18-security.md"};function o(d,a,h,n,s,c){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="_18-セキュリティとアカウント管理" tabindex="-1">18. セキュリティとアカウント管理 <a class="header-anchor" href="#_18-セキュリティとアカウント管理" aria-label="Permalink to &quot;18. セキュリティとアカウント管理&quot;">​</a></h1><p>POSLAのセキュリティ機能とアカウント管理のベストプラクティスについて説明します。</p><h2 id="_18-1-認証とセッション管理" tabindex="-1">18.1 認証とセッション管理 <a class="header-anchor" href="#_18-1-認証とセッション管理" aria-label="Permalink to &quot;18.1 認証とセッション管理&quot;">​</a></h2><h3 id="ログイン認証" tabindex="-1">ログイン認証 <a class="header-anchor" href="#ログイン認証" aria-label="Permalink to &quot;ログイン認証&quot;">​</a></h3><ul><li>ユーザー名（またはメールアドレス）＋パスワードで認証</li><li>ログイン成功時にセッションIDが再生成されます（セッション固定攻撃対策）</li><li>ログイン履歴が記録されます</li></ul><h3 id="セッションの有効期限" tabindex="-1">セッションの有効期限 <a class="header-anchor" href="#セッションの有効期限" aria-label="Permalink to &quot;セッションの有効期限&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定</th><th>値</th></tr></thead><tbody><tr><td>セッション有効時間</td><td>8時間</td></tr><tr><td>無操作タイムアウト警告</td><td>25分</td></tr><tr><td>自動ログアウト</td><td>無操作30分</td></tr></tbody></table><p><strong>タイムアウトの流れ：</strong></p><ol><li>25分間操作がないと警告モーダルが表示されます：「セッションタイムアウト — 5分以内に操作がないとログアウトされます」</li><li>「操作を続ける」ボタンを押すとセッションがリセットされます</li><li>5分以内に操作がない場合、自動的にログアウトされログイン画面にリダイレクトされます</li><li>通常の操作（クリック、キー入力、スクロール、タッチ）を行っている限り、タイマーは自動リセットされます</li></ol><h3 id="マルチデバイスログイン" tabindex="-1">マルチデバイスログイン <a class="header-anchor" href="#マルチデバイスログイン" aria-label="Permalink to &quot;マルチデバイスログイン&quot;">​</a></h3><ul><li>同じアカウントで複数端末から同時ログイン可能</li><li>ログイン時に他端末でのセッションが検知されると警告メッセージが表示されます</li><li>アクティブセッション数が表示されます</li></ul><h3 id="リモートログアウト" tabindex="-1">リモートログアウト <a class="header-anchor" href="#リモートログアウト" aria-label="Permalink to &quot;リモートログアウト&quot;">​</a></h3><p>マネージャー以上のロールは、他端末のセッションを強制終了できます。</p><ul><li>監査ログ画面でアクティブセッション一覧を確認</li><li>不要なセッションの「ログアウト」ボタンで無効化</li><li>対象端末は次回操作時にログイン画面にリダイレクトされます</li></ul><hr><h2 id="_18-2-複数店舗管理とロール権限" tabindex="-1">18.2 複数店舗管理とロール権限 <a class="header-anchor" href="#_18-2-複数店舗管理とロール権限" aria-label="Permalink to &quot;18.2 複数店舗管理とロール権限&quot;">​</a></h2><p>POSLAは複数店舗を1つの企業アカウントで管理できます。店舗ごとにデータは分離されており、各ユーザーは所属する店舗のデータだけにアクセスできます。</p><h3 id="ロールベースアクセス制御" tabindex="-1">ロールベースアクセス制御 <a class="header-anchor" href="#ロールベースアクセス制御" aria-label="Permalink to &quot;ロールベースアクセス制御&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ロール</th><th>アクセス範囲</th></tr></thead><tbody><tr><td>オーナー</td><td>企業アカウント内の全店舗・全機能</td></tr><tr><td>マネージャー</td><td>所属店舗の管理機能</td></tr><tr><td>スタッフ</td><td>所属店舗の限定機能（シフト・勤怠・POS操作）</td></tr></tbody></table><h3 id="店舗切替" tabindex="-1">店舗切替 <a class="header-anchor" href="#店舗切替" aria-label="Permalink to &quot;店舗切替&quot;">​</a></h3><p>オーナーはオーナーダッシュボードの店舗選択ドロップダウンから、管理する店舗を切り替えられます。レポート・シフト・AIアシスタント等のタブは選択中の店舗のデータを表示します。</p><h3 id="店舗間のデータ分離" tabindex="-1">店舗間のデータ分離 <a class="header-anchor" href="#店舗間のデータ分離" aria-label="Permalink to &quot;店舗間のデータ分離&quot;">​</a></h3><ul><li>マネージャー・スタッフは自分が所属する店舗のデータのみ閲覧・編集できます</li><li>他店舗の売上・注文・スタッフ情報にはアクセスできません</li><li>オーナーのみが全店舗を横断してデータを確認できます</li></ul><hr><h2 id="_18-3-sqlインジェクション対策" tabindex="-1">18.3 SQLインジェクション対策 <a class="header-anchor" href="#_18-3-sqlインジェクション対策" aria-label="Permalink to &quot;18.3 SQLインジェクション対策&quot;">​</a></h2><p>全てのSQLクエリはプリペアドステートメント（バインドパラメータ）を使用しています。例外はありません。</p><hr><h2 id="_18-4-xss対策" tabindex="-1">18.4 XSS対策 <a class="header-anchor" href="#_18-4-xss対策" aria-label="Permalink to &quot;18.4 XSS対策&quot;">​</a></h2><p>HTMLへの動的挿入は全て<code>Utils.escapeHtml()</code>関数を通してエスケープされます。</p><hr><h2 id="_18-5-冪等性キー" tabindex="-1">18.5 冪等性キー <a class="header-anchor" href="#_18-5-冪等性キー" aria-label="Permalink to &quot;18.5 冪等性キー&quot;">​</a></h2><p>セルフオーダーの注文送信には冪等性キー（Idempotency Key）が使用されます。ネットワーク障害でリトライが発生しても、同じ注文が重複して作成されることはありません。</p><hr><h2 id="_18-6-アカウント管理のベストプラクティス" tabindex="-1">18.6 アカウント管理のベストプラクティス <a class="header-anchor" href="#_18-6-アカウント管理のベストプラクティス" aria-label="Permalink to &quot;18.6 アカウント管理のベストプラクティス&quot;">​</a></h2><h3 id="_1人1アカウント-必須" tabindex="-1">1人1アカウント（必須） <a class="header-anchor" href="#_1人1アカウント-必須" aria-label="Permalink to &quot;1人1アカウント（必須）&quot;">​</a></h3><p>POSLAを利用する全スタッフに個別のユーザーアカウントを作成してください。「kitchen」「hall」などの共有アカウントは禁止です。</p><p><strong>理由：</strong></p><ul><li>監査ログが「誰が操作したか」を追跡します</li><li>勤怠打刻がスタッフ個人に紐づきます</li><li>スタッフ評価レポートが個人単位で集計されます</li><li>シフト管理が個人単位で行われます</li></ul><h3 id="パスワード管理" tabindex="-1">パスワード管理 <a class="header-anchor" href="#パスワード管理" aria-label="Permalink to &quot;パスワード管理&quot;">​</a></h3><ul><li>初期パスワードはオーナーまたはマネージャーが設定し、口頭でスタッフに伝えます</li><li>スタッフは初回ログイン後に<strong>画面右上の「パスワード変更」ボタン</strong>から自分でパスワードを変更できます</li><li>推測されやすいパスワード（1234、password等）は避けてください</li></ul><h3 id="パスワードポリシー" tabindex="-1">パスワードポリシー <a class="header-anchor" href="#パスワードポリシー" aria-label="Permalink to &quot;パスワードポリシー&quot;">​</a></h3><p>POSLAでは以下のパスワード要件をシステム側で強制しています。要件を満たさないパスワードは登録・変更できません。</p><table tabindex="0"><thead><tr><th>要件</th><th>内容</th></tr></thead><tbody><tr><td>最低長</td><td><strong>8文字以上</strong></td></tr><tr><td>英字</td><td><strong>A-Z または a-z を1文字以上</strong>含む</td></tr><tr><td>数字</td><td><strong>0-9 を1文字以上</strong>含む</td></tr></tbody></table><p>例：<code>tanaka123</code> ✅ / <code>Yamada2026</code> ✅ / <code>shibuya2024</code> ✅ NG例：<code>abcdefgh</code>（数字なし）、<code>12345678</code>（英字なし）、<code>abc123</code>（8文字未満）</p><div class="tip custom-block"><p class="custom-block-title">適用範囲</p><p>パスワードポリシーは以下の操作で全て適用されます。</p><ul><li>新規ユーザー作成時（オーナー / マネージャーが他のスタッフを作成）</li><li>既存ユーザーのパスワード更新（オーナー / マネージャーがリセット）</li><li>自分のパスワード変更（画面右上の「パスワード変更」ボタン）</li><li>POSLA管理者の自己パスワード変更</li></ul></div><h3 id="自分のパスワード変更によるセッション保護" tabindex="-1">自分のパスワード変更によるセッション保護 <a class="header-anchor" href="#自分のパスワード変更によるセッション保護" aria-label="Permalink to &quot;自分のパスワード変更によるセッション保護&quot;">​</a></h3><p>「パスワード変更」ボタンから自分でパスワードを変更すると、セキュリティのため<strong>他の端末でログイン中の同じアカウントのセッションが自動的に無効化</strong>されます。</p><ul><li>いま操作している端末はそのまま継続して使えます</li><li>他の端末（共有タブレット等）は次回操作時にログイン画面にリダイレクトされます</li><li>パスワード漏洩の疑いがある場合は、まず自分でパスワードを変更することで他端末を遮断できます</li></ul><h3 id="退職者のアカウント処理" tabindex="-1">退職者のアカウント処理 <a class="header-anchor" href="#退職者のアカウント処理" aria-label="Permalink to &quot;退職者のアカウント処理&quot;">​</a></h3><p>スタッフが退職した場合：</p><ol><li>アカウントを<strong>無効化</strong>します（削除ではなく無効化を推奨）</li><li>アクティブセッションがあれば<strong>リモートログアウト</strong>します</li><li>無効化したアカウントではログインできなくなります</li><li>過去の監査ログ・勤怠記録は保持されます</li></ol><h3 id="共有端末の管理" tabindex="-1">共有端末の管理 <a class="header-anchor" href="#共有端末の管理" aria-label="Permalink to &quot;共有端末の管理&quot;">​</a></h3><p>KDSやPOSレジなど共有タブレットを使用する場合：</p><ul><li>退勤時には必ずログアウトしてください</li><li>ログアウトしないと、次のスタッフの操作が前のスタッフのアカウントで記録されます</li><li>出退勤ボタンを押してからログアウトする習慣をつけてください</li></ul>',54)])])}const p=t(r,[["render",o]]);export{b as __pageData,p as default};
